text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 smoke 통과 시 금요일 15:00 KST로 정했다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경한다.",
        "result": "거절"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일에 릴리스한다.",
        "status": "내부 스트레치 목표로만 언급됨",
        "note": "최종 공개 릴리스 결정은 아님."
      },
      {
        "goal": "README 설치 단계를 목요일까지 검토한다.",
        "status": "가능하면 검토",
        "note": "소유자는 지정되지 않음."
      }
    ],
    "non_decisions": [
      {
        "item": "수요일 릴리스 여부",
        "status": "미결정"
      },
      {
        "item": "README 설치 단계 검토 담당자",
        "status": "미지정"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
      }
    ],
    "context_notes": [
      {
        "note": "고객명, 외부 파트너명, 예산, 보안 사고, 운영 장애, 법무 승인 요구사항은 언급되지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "명시됨"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "미할당",
      "source_certainty": "명시됨, 그러나 소유자 미지정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 게시 후 generated tarball 경로를 확인한다.",
      "due": "미정",
      "status": "대기",
      "source_certainty": "명시됨, 구체적 기한 없음"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Friday 10:00 KST 이전에 Minjun의 smoke 재실행 결과를 확인한다.",
      "Friday 12:00 KST까지 Doyun의 failure triage note 작성 여부를 확인한다.",
      "Hara가 확인할 generated tarball 경로가 올바른지 smoke 결과와 함께 검증한다.",
      "README 설치 단계 검토 담당자를 따로 지정해야 하는지 확인한다.",
      "최종 릴리스 승인 권한과 릴리스 노트의 수요일 목표 언급 여부를 결정한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너명",
      "예산 정보",
      "보안 사고 또는 보안 승인 사실",
      "운영 장애 또는 프로덕션 중단 사실",
      "법무 승인 요구사항",
      "명시되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": [
    "이 회의 메모에 없는 고객, 예산, 보안, 장애, 법무, owner, deadline 사실은 추가하지 않는다.",
    "Wednesday는 공개 릴리스 확정일이 아니라 내부 스트레치 목표로만 기록한다.",
    "confirmed decision, rejected proposal, internal stretch goal, risk, open question을 서로 섞지 않는다.",
    "tarball 경로나 승인 권한은 추측하지 않는다.",
    "README 검토는 언급되었지만 소유자가 없으므로 owner를 임의 지정하지 않는다."
  ]
}
